om a WordPress export file.'=>'استيراد <strong> المقالات والصفحات والتعليقات والحقول المخصصة والتصنيفات والوسوم </strong> من ملف تصدير ووردبريس.','Displays as a dropdown'=>'عرض كقائمة منسدلة','Uncategorized'=>'غير مصنف','Search'=>'بحث','&mdash; No Change &mdash;'=>'&mdash; بدون تغيير &mdash;','(no parent)'=>'(بدون أب)','calendar caption%1$s %2$s'=>'%1$s %2$s','Custom post types'=>'أنواع الصفحات المخصصة CPT','The front page URL contains the language code instead of the page name or page id'=>'يتضمن رابط الصفحة الأمامية رمز اللغة بدلاً من اسم الصفحة أو رقمها','Sticky posts'=>'مقالات مُثبتة','Settings saved.'=>'تم حفظ الإعدادات.','Code'=>'كود Code']];